// Issues #1 #2 #4 #5 fixed; Issue #10 TLE age added
const deg2rad = Math.PI / 180;
const Re = 6371, h = 550;
const OBSERVER_LAT = 51.0447;   // Calgary, AB — change via Settings page in AllCharts
const OBSERVER_LON = -114.0719;
const obs_lat = OBSERVER_LAT * deg2rad;
const obs_lon = OBSERVER_LON * deg2rad;

// Issue #5: use pre-parsed array (set once on fetch, not re-parsed every tick)
const parsedSats = global.get('parsedSats');
if (!parsedSats || parsedSats.length === 0) return null;

const now  = Date.now();
const GAST = (280.46061837 + 360.98564736629 * (now - 946728000000) / 86400000) % 360;

let hist = global.get('satHistory') || {};
const sats = [];

for (const sat of parsedSats) {
    const { name, n, inc, raan, argp, M0, epoch } = sat;
    const M    = (M0 + n * (now - epoch) / 86400000 * 360) % 360;
    const u    = (argp + M) * deg2rad;
    const ir   = inc * deg2rad;
    const slat = Math.asin(Math.max(-1, Math.min(1, Math.sin(ir) * Math.sin(u))));
    // Issue #2 fix: correct normalization handles both > 180 and < -180
    let slon = ((raan + Math.atan2(Math.cos(ir)*Math.sin(u), Math.cos(u))/deg2rad) - GAST + 540) % 360 - 180;

    const dlon  = slon * deg2rad - obs_lon;
    const cos_c = Math.sin(obs_lat)*Math.sin(slat) + Math.cos(obs_lat)*Math.cos(slat)*Math.cos(dlon);
    if (cos_c < Re/(Re+h)) continue;
    const c  = Math.acos(Math.max(-1, Math.min(1, cos_c)));
    const el = Math.atan((cos_c - Re/(Re+h)) / Math.sin(c)) / deg2rad;
    if (el <= 0) continue;
    const az = (Math.atan2(
        Math.sin(dlon)*Math.cos(slat),
        Math.cos(obs_lat)*Math.sin(slat) - Math.sin(obs_lat)*Math.cos(slat)*Math.cos(dlon)
    ) / deg2rad + 360) % 360;
    const lat = +(slat/deg2rad).toFixed(3);
    const lon = +slon.toFixed(3);
    if (!hist[name]) hist[name] = [];
    hist[name].push({t:now, el:+el.toFixed(2), az:+az.toFixed(2), lat, lon});
    hist[name] = hist[name].filter(p=>(now-p.t)<60000).slice(-20);
    sats.push({name, inc:+inc.toFixed(1), el:+el.toFixed(2), az:+az.toFixed(2), lat, lon, trail:hist[name]});
}

// Issue #4 fix: prune dead satellite keys from satHistory
const visibleNames = new Set(sats.map(s => s.name));
Object.keys(hist).forEach(k => { if (!visibleNames.has(k)) delete hist[k]; });
global.set('satHistory', hist);

sats.sort((a,b) => b.el - a.el);
const tleFetchedAt = global.get('tleFetchedAt') || 0;
const tleAgeMs = now - tleFetchedAt;
return [{ payload: { sats: sats.slice(0,300), meta: { count:sats.length, tleAgeMs, ts:now } } }];

// Save the raw text into global memory so other nodes can access it
global.set("rawStarlinkData", msg.payload.toString());
return null; // Stop the message here so it doesn't trigger the map graph yet

// Check if local cache is fresh enough (< 2 hours)
// Issue #5: also pre-parse CSV on load
const CACHE = '/data/starlink_tle_cache.csv';
const TWO_HOURS = 2 * 60 * 60 * 1000;
try {
    const stat = fs.statSync(CACHE);
    const age  = Date.now() - stat.mtimeMs;
    if (age < TWO_HOURS) {
        const data = fs.readFileSync(CACHE, 'utf8');
        global.set('rawStarlinkData', data);
        global.set('parsedSats', parseCsv(data));
        global.set('tleFetchedAt', stat.mtimeMs);
        global.set('satHistory', {});
        node.status({fill:'green', shape:'dot', text:`cache ${Math.round(age/60000)}m old`});
        return null;
    }
} catch(e) { /* no cache yet */ }
return msg;

function parseCsv(raw) {
    return raw.split('\n').slice(1).map(line => {
        const r = line.split(',');
        if (r.length < 9 || !r[0] || !r[0].startsWith('STARLINK')) return null;
        const n=+r[3], inc=+r[5], raan=+r[6], argp=+r[7], M0=+r[8];
        if ([n,inc,raan,argp,M0].some(isNaN)) return null;
        // Issue #1 fix: append Z so epoch is parsed as UTC, not local time
        const epoch = new Date(r[2].trim() + 'Z').getTime();
        if (!epoch || isNaN(epoch)) return null;
        return { name:r[0].trim(), n, inc, raan, argp, M0, epoch };
    }).filter(Boolean);
}

// Route: success → port 1, HTTP error → port 2 (cache fallback)
if (msg.error || (msg.statusCode && msg.statusCode !== 200)) {
    node.warn('HTTP fetch failed (' + (msg.error || msg.statusCode) + ') — trying cache');
    return [null, msg];
}
return [msg, null];

// Issue #1, #5: Save TLE, parse once on fetch
const CACHE = '/data/starlink_tle_cache.csv';
const now = Date.now();
try { fs.writeFileSync(CACHE, msg.payload); } catch(e) { node.warn('Cache write failed: ' + e.message); }
global.set('rawStarlinkData', msg.payload);
global.set('parsedSats', parseCsv(msg.payload));
global.set('tleFetchedAt', now);
global.set('satHistory', {});
node.status({fill:'blue', shape:'dot', text:`fetched ${new Date(now).toLocaleTimeString()}`});
return null;

